-- Fix prediction_type constraint: add types generated by scoring engine
-- that were missing from the original constraint.
-- Also normalise halftime -> half_time to match scoring-engine output.

ALTER TABLE public.predictions
  DROP CONSTRAINT IF EXISTS predictions_prediction_type_check;

ALTER TABLE public.predictions
  ADD CONSTRAINT predictions_prediction_type_check
  CHECK (prediction_type IN (
    'result',
    'btts',
    'over_under',
    'handicap',
    'corners',
    'cards',
    'half_time',
    'double_chance',
    'correct_score',
    'first_team_to_score',
    'clean_sheet'
  ));
